var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"11:32 ARC-KP1 \\n어느 폐건물 \\n<color=#ff3636>사건 발생</color> 11시간 경과","JPN":"11:32 ARC-KP1 \\nとある廃墟\\n<color=#ff3636>事件発生から</color>11時間経過","ENG":"[[","TWN":"11:32 ARC-KP1\\n某個廢棄建築\\n<color=#ff3636>事件發生</color>經過11小時","THA":"11.32 น. ARC-KP1\\nตึกร้างไม่ทราบชื่อ\\n11 ชั่วโมงหลัง<color=#ff3636>เกิดเหตุ</color>","VTN":"11:32 ARC-KP1\\nTòa nhà bỏ hoang không xác định\\n11 giờ sau<color=#ff3636>Sự Cố</color>","SCN":"11:32 ARC-KP1\\n某个废弃建筑\\n<color=#ff3636>事件发生</color>经过11小时","DEU":"11:32 Uhr ARC-KP1 \\nEin abgerissenes Gebäude \\n11 Stunden nach dem <color=#ff3636>Ereignis</color>","FRA":"11h32 ARC-KP1\\nDans un immeuble abandonné\\n11 heures après l'<color=#ff3636>incident</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하아……. 하아……. 숨이 찰 때까지 달려 본 건 처음이에요.","JPN":"はあ……はあ……息切れするほど走ったのは初めてです。","ENG":"*Huff... Huff...* I don’t think I’ve ever run so much in my life.","TWN":"呼呼……呼呼……我還是第一次跑到這樣上氣不接下氣呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"감찰과는 무사히 따돌렸습니다. 두 사람이 제 역할을 해 준 모양이네요.","JPN":"監察課の追跡は無事かわしました。あの二人が役割を果たしてくれたみたいですね。","ENG":"We've successfully gotten the Investigation goons off our tail. Looks like those two are fending them off pretty well.","TWN":"監察科沒有追上來，看來他們兩個的策略成功。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그런데 여기는…… 어디죠?","JPN":"ところで、ここは……どこでしょう？","ENG":"Um, so... Where are we?","TWN":"不過……這裡是哪裡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"제가 평소에 만들어 둔 아지트입니다.","JPN":"私が以前から確保しておいたアジトです。","ENG":"This is a hideout I made during my free time.","TWN":"這是我的秘密基地。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"잠시 쉬죠. 감찰과 무전을 도청 중이니 접근하면 바로 알 수 있어요.","JPN":"少し休みましょう。監察課の無線を盗聴しているので、\\n近づかれたらすぐにわかるはずです。","ENG":"Let’s rest here. I’m listening in on their radio, so we’ll know if they’re close.","TWN":"老大你先休息一下，我正在竊聽監察科的無線電，萬一他們找到這裡來，我馬上就可以知道。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 네. 고마워요, 초원 씨.","JPN":"はい。ありがとうございます、ナオさん。","ENG":"Okay. Thank you, Chowon.","TWN":"好的，謝謝你，初源。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"실장님과는 통화하셨나요? 위기대응 부서로 이관되기 전에 어서 대처해야 할 텐데요.","JPN":"室長とは連絡がとれましたか？\\n危機管理部に移管される前に、急いで対処しなければなりません。","ENG":"Have you called Chief yet? We need to resolve this before it’s transferred to the Crisis Response Department.","TWN":"你和室長通過電話了嗎？必須在移交給危機處理小組前，趕快處理好。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"오는 동안 계속 연락해 봤는데 응답이 없어요.","JPN":"来る途中もずっと連絡してみましたが、応答がありません。","ENG":"I’ve been trying, but she’s not answering.","TWN":"我在來的路上有一直試著聯絡李珍姐，但都聯絡不上。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"지금까지 이런 적은 없었는데…….","JPN":"今までこんなことは無かったのに……","ENG":"This hasn’t happened before...","TWN":"她從來沒有這樣過……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……아쉽게도 그건 좀 어려울 것 같군요.","JPN":"……残念ですが、それはちょっと難しいかと。","ENG":"...I’m afraid that might be difficult.","TWN":"……很抱歉，可能沒辦法。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"연회가 끝나고 부회장님께서 따로 호출하셔서요.","JPN":"宴会の後は、副会長に呼び出されていますので。","ENG":"The Vice Chairman wants to see me after the banquet is over.","TWN":"宴會結束後，副會長另外有事找我。"},"stage":{"bg":"GAUNTLET","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이진 언니는 연회 이후에 숙부님을 만나러 간다고 하셨어요.","JPN":"ホノカさんは宴会の後、叔父様に会うと言っていました。","ENG":"Jin told me she was meeting the Vice Chairman after the banquet.","TWN":"李珍姐說她宴會結束後要去找叔叔。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하지만 숙부님이 정말 돌아가셨다면…….","JPN":"叔父様が本当に亡くなったのなら……","ENG":"But if Uncle is really dead...","TWN":"可是叔叔已經死了……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"같이 있던 이진 언니까지 무슨 일에 휘말렸을지도 몰라요.","JPN":"一緒にいたホノカさんまで巻き込まれたのかもしれません。","ENG":"Jin might also be in some kind of trouble.","TWN":"那李珍姐會不會也發生什麼事？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"……그럴 수도 있겠군요.","JPN":"……その可能性はありますね。","ENG":"You might be right.","TWN":"……也是不無可能。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};